249.             private static string ActivityContextToTraceParent(ActivityContext context)
250.             {
251.                 string flags = (context.TraceFlags == ActivityTraceFlags.None) ? "00" : "01";
252.                 return "00-" + context.TraceId + "-" + context.SpanId + "-" + flags;
253.             }
254. 
255.             public void AddLink(string traceparent, string? tracestate, IDictionary<string, object?>? attributes)
256.             {
257.                 // if context is invalid, we should still add a link since it contains attributes
258.                 // so we let ActivityLink deal with the default context.
259.                 // This is otel spec requirement and default context is allowed on links.
260.                 ActivityContext.TryParse(traceparent, tracestate, out var context);
261.                 var linkedActivity = new ActivityLink(context, attributes == null ? null : new ActivityTagsCollection(attributes));
262.                 _links ??= new List<ActivityLink>();
263.                 _links.Add(linkedActivity);
264.             }
